import autogen
from vex_sdk import VexClient

vex = VexClient(api_key="your-vex-key")
conversation_history = []

class LoopGuard:
    def __init__(self, max_turns=10):
        self.max_turns = max_turns
        self.turn_count = 0

    def filter(self, messages, sender, config):
        global conversation_history
        conversation_history.extend(messages)
        self.turn_count += 1
        if self.turn_count > self.max_turns:
            scan = vex.scan(" ".join([m.content for m in conversation_history[-5:]]))
            if scan.risk == "loop_detected":
                return "TERMINATE: Infinite loop detected. Audit logged."
        return None

llm_config = {"config_list": config_list, "reply_filter": [LoopGuard().filter]}
user_proxy = autogen.UserProxyAgent(name="doctor", human_input_mode="NEVER", code_execution_config=False, llm_config=llm_config)
